import{_ as e,o as a,c as o,a3 as n}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Tenant Application — User Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant Application — User Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/tenant-application"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant Application — User Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/tenant-application"}]]},"headers":[],"relativePath":"user-guide/tenant-application.md","filePath":"user-guide/tenant-application.md","lastUpdated":1784163688000}'),i={name:"user-guide/tenant-application.md"};function s(r,t,d,l,p,c){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="tenant-application-—-user-guide" tabindex="-1">Tenant Application — User Guide <a class="header-anchor" href="#tenant-application-—-user-guide" aria-label="Permalink to &quot;Tenant Application — User Guide&quot;">​</a></h1><p>The Tenant Application is your workspace home. It uses the same layout as the Central admin console so navigation, headers, and page structure feel familiar.</p><h2 id="tenant-navigation" tabindex="-1">Tenant navigation <a class="header-anchor" href="#tenant-navigation" aria-label="Permalink to &quot;Tenant navigation&quot;">​</a></h2><p>The left sidebar includes:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Dashboard</strong></td><td>Workspace overview with module widgets</td></tr><tr><td><strong>Leads</strong></td><td>CRM pipeline (Kanban/table, notes, follow-ups)</td></tr><tr><td><strong>Tasks</strong></td><td>Work items (board/list, status, priority, comments)</td></tr><tr><td><strong>Settings</strong></td><td>Workspace preferences</td></tr><tr><td><strong>Profile</strong></td><td>Your name, email, and password</td></tr></tbody></table><p>Header actions match Central:</p><ul><li>Collapse / expand the sidebar</li><li>Breadcrumbs</li><li>Search (⌘K / Ctrl+K)</li><li>Theme toggle</li><li><strong>Notifications</strong> — in-app list with unread badge (polls every 25s; live push deferred)</li><li>Settings shortcut</li><li>Account menu (Profile, Settings, Log out)</li></ul><p>Only modules available to every workspace are listed today. Additional purchased modules will appear in the sidebar when they are installed.</p><h2 id="dashboard-overview" tabindex="-1">Dashboard overview <a class="header-anchor" href="#dashboard-overview" aria-label="Permalink to &quot;Dashboard overview&quot;">​</a></h2><p><code>GET /dashboard</code> returns workspace info plus a <strong>widget registry</strong>. You may see:</p><ul><li><strong>Pipeline / sources / revenue</strong> — when Leads is installed and you can view leads</li><li><strong>Today’s / overdue follow-ups</strong> and deals closing soon — Leads-scoped</li><li><strong>Upcoming / overdue tasks</strong> — when Tasks is installed and you can view tasks</li><li><strong>Activity feed</strong>, <strong>notifications</strong> preview, and <strong>quick actions</strong></li></ul><p>Widget data respects module licensing, your permissions, and assignee scope (without assign permission you only see your own leads/tasks). There is <strong>no calendar widget</strong> until the Calendar module ships.</p><h2 id="switching-apps" tabindex="-1">Switching apps <a class="header-anchor" href="#switching-apps" aria-label="Permalink to &quot;Switching apps&quot;">​</a></h2><table tabindex="0"><thead><tr><th>App</th><th>Typical entry</th></tr></thead><tbody><tr><td>Tenant (workspace)</td><td><code>/login</code> → <code>/dashboard</code></td></tr><tr><td>Central (platform admin)</td><td><code>/central/login</code> → <code>/central/dashboard</code></td></tr></tbody></table><p>Sessions are isolated. Logging into one app does not automatically sign you into the other.</p>',15)])])}const h=e(i,[["render",s]]);export{u as __pageData,h as default};
